import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.Bb4_ZWqO.js";const u=JSON.parse('{"title":"Architecture","description":"High-level system design, data flow, protocol specification, and learning path.","frontmatter":{"title":"Architecture","order":1,"description":"High-level system design, data flow, protocol specification, and learning path."},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),p={name:"architecture.md"};function l(i,a,r,c,o,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><blockquote><p><strong>New to datasole?</strong> Start with the <a href="./tutorials">Tutorials</a> — they&#39;ll get you from zero to a running app faster than reading architecture docs. Come back here when you&#39;re curious about <em>why</em> things work the way they do.</p></blockquote><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Start here</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Tutorials ──────────── Run your first server + client in 2 minutes</span></span>
<span class="line"><span>    │                  Build up to a full real-time app in 10 steps</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Examples ───────────── Copy-paste recipes organized by pattern</span></span>
<span class="line"><span>    │                  (RPC, events, live state, CRDT, combos)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Client API / Server API   Comprehensive reference for every method</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Architecture (you are here)   Why the protocol, worker, and sync</span></span>
<span class="line"><span>    │                          model work the way they do</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>State Backends / Metrics      Swap persistence, wire up observability</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>ADRs (decisions.md) ──────── The full rationale for every major choice</span></span></code></pre></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Datasole is a full-stack TypeScript framework for realtime applications. It provides synchronized server-to-client data structures, bidirectional events, concurrent RPC, and CRDT-based bidirectional sync — all over a single binary WebSocket connection.</p><h2 id="data-flow-patterns" tabindex="-1">Data Flow Patterns <a class="header-anchor" href="#data-flow-patterns" aria-label="Permalink to &quot;Data Flow Patterns&quot;">​</a></h2><p>Datasole supports seven composable patterns. Use one, or combine them freely on a single connection:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  1. RPC              client ──request──► server ──response──►   │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  2. Server events    server ────broadcast────► all clients      │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  3. Client events    client ────event────► server               │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  4. Live state       server ──JSON Patch──► client (auto-sync)  │</span></span>
<span class="line"><span>│      (s→c)                                                      │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  5. Live state       client ──JSON Patch──► server              │</span></span>
<span class="line"><span>│      (c→s)                                                      │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  6. CRDT sync        client ◄──merge──► server (conflict-free)  │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  7. Combinations     any of the above, simultaneously           │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>The most common pattern for real-world apps is <strong>client → server RPC + server → client live state</strong>: the client sends actions, the server processes them and updates its model, and all clients see a live mirror. See <a href="./tutorials#4-live-state--a-server-synced-dashboard">Tutorial 4</a> and <a href="./tutorials#10-putting-it-all-together--a-collaborative-task-board">Tutorial 10</a>.</p><h2 id="system-diagram" tabindex="-1">System Diagram <a class="header-anchor" href="#system-diagram" aria-label="Permalink to &quot;System Diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Browser                           │</span></span>
<span class="line"><span>│  ┌──────────────┐      ┌──────────────────────────┐ │</span></span>
<span class="line"><span>│  │  Main Thread  │◄────►│      Web Worker          │ │</span></span>
<span class="line"><span>│  │              │ SAB/  │  ┌────────────────────┐  │ │</span></span>
<span class="line"><span>│  │ DatasoleClient│ PM   │  │  WebSocket (binary) │  │ │</span></span>
<span class="line"><span>│  │ StateStore   │      │  │  pako decompress    │  │ │</span></span>
<span class="line"><span>│  │ CrdtStore    │      │  │  Frame decode       │  │ │</span></span>
<span class="line"><span>│  │ RPC Client   │      │  └─────────┬──────────┘  │ │</span></span>
<span class="line"><span>│  └──────────────┘      │  └─────────┼─────────────┘ │</span></span>
<span class="line"><span>└──────────────────────────────────────┼───────────────┘</span></span>
<span class="line"><span>                                       │ Binary frames</span></span>
<span class="line"><span>                                       │ (pako compressed)</span></span>
<span class="line"><span>┌──────────────────────────────────────┼───────────────┐</span></span>
<span class="line"><span>│                   Server              │               │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────┴────────────┐ │</span></span>
<span class="line"><span>│  │              DatasoleServer                      │ │</span></span>
<span class="line"><span>│  │  ┌──────────┐ ┌──────────┐ ┌─────────────────┐ │ │</span></span>
<span class="line"><span>│  │  │ WsServer │ │ RPC      │ │ State Manager   │ │ │</span></span>
<span class="line"><span>│  │  │ (ws lib) │ │ Dispatch │ │ (JSON Patch)    │ │ │</span></span>
<span class="line"><span>│  │  └──────────┘ └──────────┘ └────────┬────────┘ │ │</span></span>
<span class="line"><span>│  │  ┌──────────┐ ┌──────────┐          │          │ │</span></span>
<span class="line"><span>│  │  │ EventBus │ │ Sessions │  ┌───────┴────────┐ │ │</span></span>
<span class="line"><span>│  │  └──────────┘ └──────────┘  │ State Backend  │ │ │</span></span>
<span class="line"><span>│  │  ┌──────────┐ ┌──────────┐  │ (memory/redis/ │ │ │</span></span>
<span class="line"><span>│  │  │ Metrics  │ │ RateLimit│  │  postgres)     │ │ │</span></span>
<span class="line"><span>│  │  └──────────┘ └──────────┘  └────────────────┘ │ │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────┐  │ │</span></span>
<span class="line"><span>│  │  │ Concurrency: async|thread|pool|process    │  │ │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────┘  │ │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────┘ │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="wire-protocol" tabindex="-1">Wire Protocol <a class="header-anchor" href="#wire-protocol" aria-label="Permalink to &quot;Wire Protocol&quot;">​</a></h2><p>All communication uses binary frames with the following envelope:</p><table tabindex="0"><thead><tr><th>Byte Offset</th><th>Size</th><th>Field</th></tr></thead><tbody><tr><td>0</td><td>1</td><td>Opcode (see <code>src/shared/protocol/opcodes.ts</code>)</td></tr><tr><td>1</td><td>4</td><td>Correlation ID (uint32, big-endian)</td></tr><tr><td>5</td><td>4</td><td>Payload length (uint32, big-endian)</td></tr><tr><td>9</td><td>N</td><td>Payload (pako-compressed if above threshold)</td></tr></tbody></table><p>Opcodes cover: RPC request/response, event, state snapshot, state patch, CRDT operation, CRDT state, ping/pong, error.</p><h2 id="connection-lifecycle" tabindex="-1">Connection Lifecycle <a class="header-anchor" href="#connection-lifecycle" aria-label="Permalink to &quot;Connection Lifecycle&quot;">​</a></h2><ol><li>Client creates <code>DatasoleClient</code> and calls <code>connect()</code></li><li>Web Worker opens WebSocket to <code>wss://server/__ds</code></li><li>Server receives HTTP upgrade → <code>authHandler</code> validates credentials</li><li>On success: <code>ConnectionContext</code> created with auth identity, metadata</li><li>Concurrency strategy assigns a worker (event loop / thread / process)</li><li>Server pushes initial state snapshots</li><li>Ongoing: incremental JSON Patches, events, RPC, CRDT ops — all multiplexed</li><li>On disconnect: session flushed to persistence for future restore</li></ol><h2 id="sync-channel-architecture" tabindex="-1">Sync Channel Architecture <a class="header-anchor" href="#sync-channel-architecture" aria-label="Permalink to &quot;Sync Channel Architecture&quot;">​</a></h2><p>Sync channels decouple <em>what</em> is synchronized from <em>when</em> it&#39;s flushed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server state mutation</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  SyncChannel.enqueue(patches)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── immediate → flush now</span></span>
<span class="line"><span>        ├── batched   → flush after N ops or M ms</span></span>
<span class="line"><span>        └── debounced → flush after M ms of quiet</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>                ▼</span></span>
<span class="line"><span>        Serialize → compress → binary frame → WebSocket → client</span></span></code></pre></div><h2 id="crdt-merge-flow" tabindex="-1">CRDT Merge Flow <a class="header-anchor" href="#crdt-merge-flow" aria-label="Permalink to &quot;CRDT Merge Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client A                    Server                    Client B</span></span>
<span class="line"><span>   │                          │                          │</span></span>
<span class="line"><span>   │  op: increment(+1)       │                          │</span></span>
<span class="line"><span>   ├─────────────────────────►│  apply(op)               │</span></span>
<span class="line"><span>   │                          ├─────────────────────────►│</span></span>
<span class="line"><span>   │                          │  broadcast merged state   │</span></span>
<span class="line"><span>   │◄─────────────────────────┤                          │</span></span>
<span class="line"><span>   │  merge(state)            │◄─────────────────────────┤</span></span>
<span class="line"><span>   │                          │  op: increment(+1)       │</span></span>
<span class="line"><span>   │                          │  apply(op)               │</span></span>
<span class="line"><span>   │◄─────────────────────────┤─────────────────────────►│</span></span>
<span class="line"><span>   │  merge(state)            │  broadcast merged state   │</span></span>
<span class="line"><span>   │                          │                          │</span></span>
<span class="line"><span>   │  counter: 2              │  counter: 2              │  counter: 2</span></span></code></pre></div><p>All three nodes converge to the same value regardless of operation order.</p><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Where</th></tr></thead><tbody><tr><td>Step-by-step learning</td><td><a href="./tutorials">Tutorials</a></td></tr><tr><td>Copy-paste recipes</td><td><a href="./examples">Examples</a></td></tr><tr><td>Client methods</td><td><a href="./client">Client API</a></td></tr><tr><td>Server methods</td><td><a href="./server">Server API</a></td></tr><tr><td>Persistence options</td><td><a href="./state-backends">State Backends</a></td></tr><tr><td>Observability</td><td><a href="./metrics">Metrics</a></td></tr><tr><td>Why each decision was made</td><td><a href="./decisions">ADRs</a></td></tr></tbody></table>`,26)])])}const m=s(p,[["render",l]]);export{u as __pageData,m as default};
